// // (1) reset: Resets the counter to 12'b111111111111 when high.
// (2) enable: Disables the counter increment operation when high.
// (3) q: The value of the counter.
module top_module(
    input clk,
    input reset,
    input enable,
    output reg [11:0] q
);

    always @(posedge clk) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 12'b000000000000
            q <= 12'b000000000000;
        end else if (enable) begin
            // Counter increment: Increment by 1 when enabled
            q <= q + 1;
        end
    end

endmodule

